const inputItem = $input.first().json;
const records = inputItem.data?.items || [];

function getText(field) {
  if (!field) return "";
  if (Array.isArray(field)) {
    if (typeof field[0] === "object" && field[0] !== null) {
      return field[0]?.text || field[0]?.name || "";
    }
    return field[0] || "";
  }
  if (typeof field === "object") {
    return field.text || field.name || "";
  }
  return field;
}

function getNumber(field) {
  if (field === undefined || field === null || field === "") return 0;
  const num = Number(field);
  return Number.isNaN(num) ? 0 : num;
}

function getTimestamp(field) {
  if (field === undefined || field === null || field === "") return "";

  // 已经是数字时间戳
  if (typeof field === "number" && !Number.isNaN(field)) {
    return field;
  }

  // 可能是字符串数字
  if (typeof field === "string") {
    const trimmed = field.trim();
    if (!trimmed) return "";
    const num = Number(trimmed);
    if (!Number.isNaN(num)) return num;

    // 兜底：尝试解析日期字符串
    const parsed = new Date(trimmed).getTime();
    return Number.isNaN(parsed) ? "" : parsed;
  }

  // 可能是数组
  if (Array.isArray(field)) {
    if (field.length === 0) return "";
    return getTimestamp(field[0]);
  }

  // 可能是对象
  if (typeof field === "object") {
    if (field.timestamp !== undefined) {
      const num = Number(field.timestamp);
      return Number.isNaN(num) ? "" : num;
    }
    if (field.value !== undefined) {
      return getTimestamp(field.value);
    }
    if (field.text !== undefined) {
      return getTimestamp(field.text);
    }
  }

  return "";
}

function formatTimestamp(ts) {
  if (ts === "" || ts === undefined || ts === null) return "";
  const num = Number(ts);
  if (Number.isNaN(num)) return "";

  const d = new Date(num);
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  const hour = String(d.getHours()).padStart(2, "0");
  const minute = String(d.getMinutes()).padStart(2, "0");

  return `${year}-${month}-${day} ${hour}:${minute}`;
}

function priorityScore(priority) {
  if (priority === "High") return 3;
  if (priority === "Medium") return 2;
  return 1;
}

const now = Date.now();

const result = records
  .map(record => {
    const fields = record.fields || {};

    const taskName = getText(fields.task_name);
    const taskId = getText(fields.task_id);

    const status = Array.isArray(fields.status)
      ? fields.status[0]
      : fields.status;

    const deadlineTs = getTimestamp(fields.deadline);
    const earliestStartTs = getTimestamp(fields.earliest_start);

    const estimatedMinutes = getNumber(fields.estimated_minutes);
    const remainingMinutes =
      getNumber(fields.remaining_minutes) || estimatedMinutes || 0;

    const priority = fields.priority || "Medium";

    return {
      record_id: record.record_id,
      task_id: taskId,
      task_name: taskName,

      deadline: deadlineTs,
      deadline_readable: formatTimestamp(deadlineTs),

      estimated_minutes: estimatedMinutes,
      priority: priority,
      priority_score: priorityScore(priority),

      task_type: fields.task_type || "Life",

      earliest_start: earliestStartTs,
      earliest_start_readable: formatTimestamp(earliestStartTs),

      splittable: fields.splittable || "No",
      energy_required: fields.energy_required || "Medium",
      status: status || "Inbox",
      remaining_minutes: remainingMinutes,

      is_overdue:
        deadlineTs !== "" && !Number.isNaN(Number(deadlineTs))
          ? Number(deadlineTs) < now
          : false
    };
  })
  .filter(task => {
    // 只保留 Inbox 和 Need Reschedule
    const statusOk =
      task.status === "Inbox" ||
      task.status === "Need Reschedule";

    // 还需要有剩余时长
    const remainingOk = Number(task.remaining_minutes) > 0;

    // earliest_start 到了才能排；没填 earliest_start 也允许
    const earliestStartOk =
      !task.earliest_start ||
      Number(task.earliest_start) <= now;

    // 已过期任务先不丢掉，仍允许进入后续排程
    // 因为有些场景你可能仍然希望排“已经快来不及”的任务
    return statusOk && remainingOk && earliestStartOk;
  })
  .sort((a, b) => {
    const aDeadline = a.deadline === "" ? Number.MAX_SAFE_INTEGER : Number(a.deadline);
    const bDeadline = b.deadline === "" ? Number.MAX_SAFE_INTEGER : Number(b.deadline);

    // 1. deadline 近的优先
    if (aDeadline !== bDeadline) {
      return aDeadline - bDeadline;
    }

    // 2. priority 高的优先
    if (a.priority_score !== b.priority_score) {
      return b.priority_score - a.priority_score;
    }

    // 3. remaining_minutes 少的优先
    return Number(a.remaining_minutes) - Number(b.remaining_minutes);
  });

return result.map(t => ({ json: t }));

const items = $input.all().map(i => i.json);

const today = new Date();
const nowTs = Date.now();

// JS: 0=Sunday, 1=Monday, 2=Tuesday, 3=Wednesday...
const weekdayMap = {
  0: ["Sunday", "星期日", "周日", "周天"],
  1: ["Monday", "星期一", "周一"],
  2: ["Tuesday", "星期二", "周二"],
  3: ["Wednesday", "星期三", "周三"],
  4: ["Thursday", "星期四", "周四"],
  5: ["Friday", "星期五", "周五"],
  6: ["Saturday", "星期六", "周六"]
};

const todayIndex = today.getDay();
const todayWeekdayNames = weekdayMap[todayIndex];
const today_weekday = todayWeekdayNames[0];

function getText(field) {
  if (!field) return "";
  if (Array.isArray(field)) {
    if (typeof field[0] === "object" && field[0] !== null) {
      return field[0]?.text || field[0]?.name || "";
    }
    return field[0] || "";
  }
  if (typeof field === "object") {
    return field.text || field.name || "";
  }
  return field;
}

function getNumber(value, defaultValue = 0) {
  if (value === undefined || value === null || value === "") return defaultValue;
  const num = Number(value);
  return Number.isNaN(num) ? defaultValue : num;
}

function getTimestamp(value) {
  if (value === undefined || value === null || value === "") return "";

  if (typeof value === "number" && !Number.isNaN(value)) {
    return value;
  }

  if (typeof value === "string") {
    const trimmed = value.trim();
    if (!trimmed) return "";
    const num = Number(trimmed);
    if (!Number.isNaN(num)) return num;

    const parsed = new Date(trimmed).getTime();
    return Number.isNaN(parsed) ? "" : parsed;
  }

  if (Array.isArray(value)) {
    if (value.length === 0) return "";
    return getTimestamp(value[0]);
  }

  if (typeof value === "object") {
    if (value.timestamp !== undefined) {
      const num = Number(value.timestamp);
      return Number.isNaN(num) ? "" : num;
    }
    if (value.value !== undefined) {
      return getTimestamp(value.value);
    }
    if (value.text !== undefined) {
      return getTimestamp(value.text);
    }
  }

  return "";
}

function formatTimestamp(ts) {
  if (ts === "" || ts === undefined || ts === null) return "";
  const num = Number(ts);
  if (Number.isNaN(num)) return "";

  const d = new Date(num);
  const year = d.getFullYear();
  const month = String(d.getMonth() + 1).padStart(2, "0");
  const day = String(d.getDate()).padStart(2, "0");
  const hour = String(d.getHours()).padStart(2, "0");
  const minute = String(d.getMinutes()).padStart(2, "0");

  return `${year}-${month}-${day} ${hour}:${minute}`;
}

function priorityScore(priority) {
  if (priority === "High") return 3;
  if (priority === "Medium") return 2;
  return 1;
}

// 1. 提取任务
const rawTasks = items.filter(i => i.record_id);

// 2. 过滤有效任务 + 标准化
const tasks = rawTasks
  .filter(t =>
    t.task_id &&
    t.task_id !== "empty" &&
    t.task_name &&
    t.task_name !== "empty" &&
    Number(t.remaining_minutes || t.estimated_minutes || 0) > 0 &&
    t.status !== "Done" &&
    t.status !== "Cancelled"
  )
  .map(t => {
    const deadlineTs = getTimestamp(t.deadline);
    const earliestStartTs = getTimestamp(t.earliest_start);
    const remainingMinutes = getNumber(
      t.remaining_minutes,
      getNumber(t.estimated_minutes, 0)
    );
    const estimatedMinutes = getNumber(t.estimated_minutes, 0);
    const priority = t.priority || "Medium";

    return {
      record_id: t.record_id,
      task_id: t.task_id,
      task_name: t.task_name,

      deadline: deadlineTs,
      deadline_readable: formatTimestamp(deadlineTs),

      estimated_minutes: estimatedMinutes,
      remaining_minutes: remainingMinutes,

      priority,
      priority_score: priorityScore(priority),

      task_type: t.task_type || "Life",

      earliest_start: earliestStartTs,
      earliest_start_readable: formatTimestamp(earliestStartTs),

      splittable: t.splittable || "No",
      energy_required: t.energy_required || "Medium",
      status: t.status || "Inbox",

      is_overdue:
        deadlineTs !== "" && !Number.isNaN(Number(deadlineTs))
          ? Number(deadlineTs) < nowTs
          : false
    };
  })
  .filter(t => {
    // earliest_start 到了才能进入今天排程；没填 earliest_start 也允许
    return !t.earliest_start || Number(t.earliest_start) <= nowTs;
  });

// 3. 去重（同 task_id 后出现的覆盖前面的）
const uniqueTasksMap = {};
for (const task of tasks) {
  uniqueTasksMap[task.task_id] = task;
}
const uniqueTasks = Object.values(uniqueTasksMap);

// 4. 排序：deadline近 > priority高 > 剩余时长短
uniqueTasks.sort((a, b) => {
  const aDeadline = a.deadline === "" ? Number.MAX_SAFE_INTEGER : Number(a.deadline);
  const bDeadline = b.deadline === "" ? Number.MAX_SAFE_INTEGER : Number(b.deadline);

  if (aDeadline !== bDeadline) {
    return aDeadline - bDeadline;
  }

  if (a.priority_score !== b.priority_score) {
    return b.priority_score - a.priority_score;
  }

  return Number(a.remaining_minutes) - Number(b.remaining_minutes);
});

// 5. 提取 availability rules
const rawRules = items.filter(i =>
  i.weekday !== undefined ||
  i.start_time !== undefined ||
  i.end_time !== undefined
);

// 6. 标准化 availability rules
const normalizedRules = rawRules
  .filter(rule => {
    const start = getText(rule.start_time);
    const end = getText(rule.end_time);
    return start && end;
  })
  .map(rule => ({
    weekday: String(getText(rule.weekday)).trim(),
    start_time: getText(rule.start_time),
    end_time: getText(rule.end_time),
    energy_level: getText(rule.energy_level),
    location: getText(rule.location),
    device: getText(rule.device)
  }));

// 7. 只保留今天的规则
const availability_rules = normalizedRules.filter(rule =>
  todayWeekdayNames.includes(rule.weekday)
);

return [
  {
    json: {
      today_date: today.toISOString().slice(0, 10),
      current_timestamp: nowTs,
      today_weekday,
      today_weekday_aliases: todayWeekdayNames,
      tasks: uniqueTasks,
      availability_rules
    }
  }
];

const items = $input.first().json.data.items;

return items.map(item => {
  return {
    json: {
      record_id: item.record_id,
      ...item.fields
    }
  };
});

const aiRaw = $input.first().json.output;
const originalTasks = $items("Filter Schedulable Tasks").map(i => i.json);

// 1. 先把 AI 输出转成真正的数组
let schedules = [];

if (Array.isArray(aiRaw)) {
  schedules = aiRaw;
} else if (typeof aiRaw === "string") {
  try {
    schedules = JSON.parse(aiRaw);
  } catch (e) {
    return [
      {
        json: {
          error: "AI output is not valid JSON",
          raw_output: aiRaw
        }
      }
    ];
  }
} else {
  return [
    {
      json: {
        error: "AI output format is unsupported",
        raw_output: aiRaw
      }
    }
  ];
}

// 2. 如果没有排程结果
if (!Array.isArray(schedules) || schedules.length === 0) {
  return [];
}

// 3. 展开成 n8n 多条 item
return schedules.map(schedule => {
  const matchedTask = originalTasks.find(
    t => t.task_id === schedule.task_id
  ) || {};

  return {
    json: {
      // 用于更新 tasks 表
      record_id: matchedTask.record_id || schedule.record_id || "",

      // 任务信息
      task_id: schedule.task_id || "",
      task_name: schedule.task_name || "",

      // 排程信息
      start_time: schedule.start_time || "",
      end_time: schedule.end_time || "",
      scheduled_minutes: Number(schedule.scheduled_minutes || 0),

      // schedule_output 表字段
      schedule_id: "SCH-" + Date.now() + "-" + Math.floor(Math.random() * 1000),
      schedule_status: "Planned",
      generated_at: new Date().toISOString(),

      // 给 Update Task Status 用
      new_task_status: "Scheduled"
    }
  };
});

